const Web3 = require('web3');
const { ethers } = require('ethers');

// Provider configuration
const provider = new Web3.providers.HttpProvider('YOUR_RPC_ENDPOINT');

// Wallet configuration
const privateKey = 'YOUR_PRIVATE_KEY';
const wallet = new ethers.Wallet(privateKey, provider);

// Contract address and ABI
const contractAddress = 'YOUR_CONTRACT_ADDRESS';
const contractABI = JSON.parse('YOUR_CONTRACT_ABI');

// Contract instance
const contract = new ethers.Contract(contractAddress, contractABI, wallet);

// Function to send ETH
async function sendETH(toAddress, amount) {
  const transaction = {
    to: toAddress,
    value: ethers.utils.parseEther(amount.toString()),
  };

  const signedTransaction = await wallet.signTransaction(transaction);
  const transactionHash = await provider.send('eth_sendRawTransaction', [signedTransaction]);

  return transactionHash;
}

// Function to interact with smart contract
async function interactWithContract(functionName, ...args) {
  const transaction = await contract[functionName](...args);
  const receipt = await transaction.wait();

  return receipt;
}